// Layered Echo — Dual-Palette Polygon Grid
// Adapted from GenerativeArtGallery layered-echo sketch
// 30 art-movement palettes across 6 moods, dual-blend,
// 4 polygon modes, chaos columns, trailing echo, glitch overlay

let le = {
  cells:[], pal:[], bg:[0,0,10], border:[0,0,20],
  gs:50, gScale:1, swl:7500,
  prevM:'', prevD:'', prevS:'', prevC:'', prevF:''
};

let lePals = {
  'warm classics': [
    ['#44344F','#313639','#E3C095','#E9E1C9','#BEBEBE'],
    ['#936639','#839073','#A67C52','#CFC493','#E5E1D4'],
    ['#EAB4CB','#B79492','#806854','#47362E','#1F1A12'],
    ['#AE7181','#655C56','#AB9597','#FFE156','#FFC542'],
    ['#8D6A53','#B38E89','#EAC8AF','#E2A987','#C77963']
  ],
  'cool futurism': [
    ['#30D5C8','#C0C1C2','#808080','#37383A','#1B1C1E'],
    ['#D10068','#FF006E','#FF77A9','#FF99C8','#FAEAFE'],
    ['#FF71CE','#01CDFE','#05FFA1','#B967FF','#FFFB96'],
    ['#031926','#468189','#77ACA2','#9DBEBB','#F4ECEC']
  ],
  'vivid pop': [
    ['#FF4F58','#FF8966','#FFAA5E','#FFD56B','#FFFF89'],
    ['#F2F3AE','#ED1567','#0096D6','#000000','#B6E6BD'],
    ['#FFB5E8','#FF9CEE','#FFCCF9','#F3B8FF','#E6B8F3'],
    ['#FF6B35','#F7C59F','#EFEEEE','#8338EC','#3A86FF'],
    ['#F72585','#B5179E','#7209B7','#560BAD','#480CA8']
  ],
  'muted earth': [
    ['#614A3E','#847567','#A09383','#BDB0A0','#D8CDBB'],
    ['#E07A5F','#3D405B','#81B29A','#F2CC8F','#E07A5F'],
    ['#DEE3E2','#89CFF0','#FCF4D9','#C1CDC1','#CDC08C'],
    ['#A7A37E','#ECDB54','#E34131','#6C461F','#A32B1C']
  ],
  'dark gothic': [
    ['#363636','#7A7979','#9E9494','#C4BEBE','#E9E9E9'],
    ['#1A1B41','#D90368','#820263','#291720','#04A777'],
    ['#4C3F54','#D13525','#F2C057','#486824','#A8C686'],
    ['#D3D5D4','#B98EA7','#995D81','#403233','#241623'],
    ['#102542','#F87060','#CDD7D6','#B3A394','#684551']
  ],
  'neon digital': [
    ['#64E9EE','#37818E','#6C464F','#A24936','#D36135'],
    ['#8D6A53','#C88D94','#E9C46A','#F4A261','#2A9D8F'],
    ['#E3AEB1','#C49592','#C49592','#774936','#2A0C0F'],
    ['#EB6C0E','#F49F0A','#F4BF92','#241623','#D3D5D4'],
    ['#D41111','#F2F5EA','#1C1A2F','#E6B600','#0076A8']
  ]
};

function leH2H(p, hex) {
  let c = p.color(hex);
  return [p.hue(c), p.saturation(c), p.brightness(c)];
}

function leComp(c) { return [(c[0]+180)%360, c[1], c[2]]; }

function leShuf(a) {
  for (let i = a.length-1; i > 0; i--) {
    let j = Math.floor(Math.random()*(i+1));
    [a[i],a[j]] = [a[j],a[i]];
  }
}

function leGenPts(p, x, y, mode, gs) {
  let pts;
  if (mode === 'wonky') {
    pts = [
      {x:x-gs/p.random(1.5,2.5), y:y-gs/p.random(1.5,2.5)},
      {x:x, y:y-gs/2},
      {x:x+gs/p.random(1.5,2.5), y:y-gs/p.random(1.5,2.5)},
      {x:x+gs/p.random(1.5,2.5), y:y},
      {x:x+gs/p.random(1.5,2.5), y:y+gs/p.random(1.5,2.5)},
      {x:x, y:y+gs/p.random(1.5,2.5)},
      {x:x-gs/p.random(1.5,2.5), y:y+gs/p.random(1.5,2.5)},
      {x:x-gs/p.random(1.5,2.5), y:y}
    ];
  } else if (mode === 'diagonal') {
    pts = [
      {x:x, y:y-gs/2},
      {x:x+gs/2, y:y-gs/4},
      {x:x+gs/2, y:y+gs/4},
      {x:x, y:y+gs/2},
      {x:x-gs/2, y:y+gs/4},
      {x:x-gs/2, y:y-gs/4}
    ];
  } else if (mode === 'staggered') {
    pts = [
      {x:x-gs/4, y:y-gs/2},
      {x:x+gs/4, y:y-gs/2},
      {x:x+gs/2, y:y},
      {x:x+gs/4, y:y+gs/2},
      {x:x-gs/4, y:y+gs/2},
      {x:x-gs/2, y:y}
    ];
  } else {
    pts = [
      {x:x-gs/2, y:y-gs/2}, {x:x, y:y-gs/2}, {x:x+gs/2, y:y-gs/2},
      {x:x+gs/2, y:y}, {x:x+gs/2, y:y+gs/2}, {x:x, y:y+gs/2},
      {x:x-gs/2, y:y+gs/2}, {x:x-gs/2, y:y}
    ];
  }
  let a = p.random(-0.2, 0.2);
  let ca = Math.cos(a), sa = Math.sin(a);
  for (let pt of pts) {
    let dx = pt.x-x, dy = pt.y-y;
    pt.x = x + dx*ca - dy*sa;
    pt.y = y + dx*sa + dy*ca;
  }
  return pts;
}

function leInit(p) {
  let mood  = p.getSynthVar('palette_mood') || 'warm classics';
  let dens  = p.getSynthVar('grid_density') || 'medium';
  let style = p.getSynthVar('cell_shape')   || 'mixed';
  let chaos = p.getSynthVar('chaos_order')  || 'balanced';
  let fx    = p.getSynthVar('post_process') || 'none';
  le.prevM = mood; le.prevD = dens; le.prevS = style;
  le.prevC = chaos; le.prevF = fx;

  p.colorMode(p.HSB, 360, 100, 100, 100);
  let group = lePals[mood] || lePals['warm classics'];
  let i1 = Math.floor(p.random(group.length));
  let i2 = Math.floor(p.random(group.length));
  while (i2 === i1 && group.length > 1) i2 = Math.floor(p.random(group.length));
  let combined = [];
  group[i1].forEach(function(h){ combined.push(leH2H(p,h)); });
  group[i2].forEach(function(h){ combined.push(leH2H(p,h)); });
  leShuf(combined);
  le.pal = combined;

  let dk = combined.reduce(function(a,b){ return a[2]<b[2]?a:b; });
  let br = combined.reduce(function(a,b){ return a[2]>b[2]?a:b; });
  let pick = p.random() < 0.5 ? dk : br;
  if (pick === br) le.bg = [pick[0], pick[1], Math.max(0,pick[2]-10)];
  else le.bg = [pick[0], pick[1], Math.min(100,pick[2]+10)];

  let bc = combined[Math.floor(p.random(combined.length))];
  le.border = [bc[0], bc[1], Math.max(0,bc[2]-20)];

  let rats;
  if (dens === 'coarse') rats = [4,5,6];
  else if (dens === 'fine') rats = [10,12,14];
  else rats = [6,7,8,9];
  le.gs = p.height / rats[Math.floor(p.random(rats.length))];

  let cc;
  if (chaos === 'orderly') cc = 0.1;
  else if (chaos === 'chaotic') cc = 0.85;
  else cc = 0.5;

  let wfCh = fx === 'wireframe mix' ? 0.15 : 0;
  le.cells = [];
  let ci = 0;
  let modes = ['wonky','diagonal','staggered','standard'];
  for (let x = le.gs; x < p.width; x += le.gs) {
    let colChaos = p.random() < cc;
    for (let y = le.gs; y < p.height; y += le.gs) {
      let col = le.pal[ci % le.pal.length].slice();
      if (p.random() < 0.33) col = leComp(col);
      ci++;
      let mode;
      if (style === 'mixed') mode = colChaos ? modes[Math.floor(p.random(modes.length))] : 'standard';
      else mode = colChaos ? modes[Math.floor(p.random(modes.length))] : style;
      let isW = p.random() < wfCh;
      le.cells.push({ col:col, isW:isW, pts:leGenPts(p,x,y,mode,le.gs) });
    }
  }
  p.background(le.bg[0], le.bg[1], le.bg[2]);
}

p.setup = function() {
  p.createCanvas(400, 400);
  p.colorMode(p.HSB, 360, 100, 100, 100);
  p.frameRate(30);
  leInit(p);
};

p.draw = function() {
  let mood  = p.getSynthVar('palette_mood') || 'warm classics';
  let dens  = p.getSynthVar('grid_density') || 'medium';
  let style = p.getSynthVar('cell_shape')   || 'mixed';
  let chaos = p.getSynthVar('chaos_order')  || 'balanced';
  let trail = p.getSynthVar('trail_effect') || 'ghosted';
  let fx    = p.getSynthVar('post_process') || 'none';

  if (mood!==le.prevM||dens!==le.prevD||style!==le.prevS||chaos!==le.prevC||fx!==le.prevF) leInit(p);

  p.noStroke();
  if (trail === 'clean') {
    p.background(le.bg[0], le.bg[1], le.bg[2]);
  } else {
    let ta = trail === 'heavy trail' ? 1.5 : 5;
    p.fill(le.bg[0], le.bg[1], le.bg[2], ta);
    p.rect(0, 0, p.width, p.height);
  }

  let t = p.millis() / 2000;
  le.gScale = 1.0 + 0.02 * p.sin(t * p.TWO_PI);
  let wt = p.millis() / le.swl;
  let cx = p.width/2, cy = p.height/2;

  for (let cell of le.cells) {
    let pts = cell.pts;
    for (let i = 0; i < pts.length; i++) {
      let pt = pts[i];
      let w1 = p.sin(p.TWO_PI * wt);
      let w2 = p.sin(p.TWO_PI * wt * 0.7);
      let cw = w1*0.5 + w2*0.5;
      let n = p.noise(pt.x*0.003, pt.y*0.003, wt);
      let no = p.map(n, 0, 1, -1, 1);
      let ax=0, ay=0;
      for (let j=0; j<pts.length; j++) {
        if (i!==j) { ax+=pts[j].x; ay+=pts[j].y; }
      }
      let cnt = pts.length-1;
      if (cnt>0) { ax/=cnt; ay/=cnt; }
      let dx=ax-pt.x, dy=ay-pt.y;
      let mg = Math.sqrt(dx*dx+dy*dy);
      let tm = cw*1.1 + no*0.5;
      if (mg>0) { pt.x += dx/mg*tm; pt.y += dy/mg*tm; }
    }

    // Shadow
    p.fill(0, 0, 0, 12);
    p.noStroke();
    p.beginShape();
    for (let pt of pts) {
      p.vertex((pt.x-cx)*le.gScale+cx+4, (pt.y-cy)*le.gScale+cy+4);
    }
    p.endShape(p.CLOSE);

    // Cell
    if (cell.isW) {
      p.noFill();
      p.stroke(cell.col[0], cell.col[1], cell.col[2], 82);
      p.strokeWeight(2);
    } else {
      p.fill(cell.col[0], cell.col[1], cell.col[2], 88);
      p.noStroke();
    }
    p.beginShape();
    for (let pt of pts) {
      p.vertex((pt.x-cx)*le.gScale+cx, (pt.y-cy)*le.gScale+cy);
    }
    p.endShape(p.CLOSE);
  }

  // Border
  p.stroke(le.border[0], le.border[1], le.border[2], 78);
  p.strokeWeight(12);
  p.noFill();
  p.rect(0, 0, p.width, p.height);

  // Glitch scanlines
  if (fx === 'glitch') {
    for (let i = 0; i < 3; i++) {
      let gy = p.random(p.height);
      let gh = p.random(2, 8);
      let gx = p.random(-15, 15);
      p.noStroke();
      p.fill(p.random(360), 50, 80, 10);
      p.rect(gx, gy, p.width+30, gh);
    }
  }
};
